class Stack:
    def __init__(self):
        self.data = []

    def push(self, item):
        self.data.append(item)       # O(1) amortized

    def pop(self):
        if self.is_empty():
            raise IndexError("Stack is empty")
        return self.data.pop()       # O(1)

    def peek(self):
        if self.is_empty():
            raise IndexError("Stack is empty")
        return self.data[-1]         # O(1)

    def is_empty(self):
        return len(self.data) == 0

    def size(self):
        return len(self.data)

class Node:
    def __init__(self, value):
        self.value = value
        self.next = None

class Stack:
    def __init__(self):
        self.top = None
        self._size = 0

    def push(self, item):
        node = Node(item)
        node.next = self.top   # new node points to old top
        self.top = node        # top now points to new node
        self._size += 1

    def pop(self):
        if self.is_empty():
            raise IndexError("Stack is empty")
        value = self.top.value
        self.top = self.top.next   # move top down
        self._size -= 1
        return value

    def peek(self):
        if self.is_empty():
            raise IndexError("Stack is empty")
        return self.top.value

    def is_empty(self):
        return self.top is None

class Node:
    def __init__(self, value):
        self.value = value
        self.next = None

class Queue:
    def __init__(self):
        self.front = None   # dequeue from here
        self.rear = None    # enqueue from here
        self._size = 0

    def enqueue(self, item):
        node = Node(item)
        if self.rear:
            self.rear.next = node   # link old rear to new node
        self.rear = node            # rear advances
        if self.front is None:
            self.front = node       # first item: front = rear
        self._size += 1

    def dequeue(self):
        if self.is_empty():
            raise IndexError("Queue is empty")
        value = self.front.value
        self.front = self.front.next   # front advances
        if self.front is None:
            self.rear = None           # queue is now empty
        self._size -= 1
        return value

    def peek(self):
        if self.is_empty():
            raise IndexError("Queue is empty")
        return self.front.value

    def is_empty(self):
        return self.front is None

class CircularQueue:
    def __init__(self, capacity):
        self.capacity = capacity
        self.data = [None] * capacity
        self.front = 0
        self.rear = 0
        self._size = 0

    def enqueue(self, item):
        if self._size == self.capacity:
            raise OverflowError("Queue is full")
        self.data[self.rear] = item
        self.rear = (self.rear + 1) % self.capacity   # wrap around
        self._size += 1

    def dequeue(self):
        if self.is_empty():
            raise IndexError("Queue is empty")
        value = self.data[self.front]
        self.front = (self.front + 1) % self.capacity
        self._size -= 1
        return value

    def is_empty(self):
        return self._size == 0

def next_greater(nums):
    result = [-1] * len(nums)
    stack = []   # stores indices
    for i, num in enumerate(nums):
        while stack and nums[stack[-1]] < num:
            idx = stack.pop()
            result[idx] = num    # num is the next greater for nums[idx]
        stack.append(i)
    return result

print(next_greater([2, 1, 5, 3, 6]))  # [5, 5, 6, 6, -1]

def is_valid(s):
    stack = []
    matching = {')': '(', ']': '[', '}': '{'}
    for char in s:
        if char in '([{':
            stack.push(char)
        elif char in ')]}':
            if not stack or stack[-1] != matching[char]:
                return False
            stack.pop()
    return len(stack) == 0

print(is_valid("{[()]}"))   # True
print(is_valid("{[(])}"))   # False
